"""Checkout endpoint (with fix: bounded downstream latency)."""

from __future__ import annotations

from .pricing import fetch_price


def checkout(item_id: str, qty: int) -> dict:
    try:
        price = fetch_price(item_id, timeout_ms=25)
    except Exception:
        price = 0.0
    return {"item_id": item_id, "qty": qty, "total": price * qty}
